function minimumEffortPath(heights) {
    const directions = [[1, 0], [0, 1], [-1, 0], [0, -1]];
    const rows = heights.length;
    const cols = heights[0].length;
    const efforts = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
    const pq = new PriorityQueue((a, b) => a[0] - b[0]);

    efforts[0][0] = 0;
    pq.offer([0, 0, 0]);

    while (!pq.isEmpty()) {
        const [effort, x, y] = pq.poll();

        if (x === rows - 1 && y === cols - 1) {
            return effort;
        }

        for (const [dx, dy] of directions) {
            const nx = x + dx;
            const ny = y + dy;
            if (nx >= 0 && nx < rows && ny >= 0 && ny < cols) {
                const newEffort = Math.max(effort, Math.abs(heights[nx][ny] - heights[x][y]));
                if (newEffort < efforts[nx][ny]) {
                    efforts[nx][ny] = newEffort;
                    pq.offer([newEffort, nx, ny]);
                }
            }
        }
    }

    return -1;
}

class PriorityQueue {
    constructor(comparator) {
        this.comparator = comparator;
        this.data = [];
    }

    offer(elem) {
        let i = this.data.length;
        this.data.push(elem);

        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (this.comparator(this.data[i], this.data[parent]) >= 0) {
                break;
            }
            [this.data[i], this.data[parent]] = [this.data[parent], this.data[i]];
            i = parent;
        }
    }

    poll() {
        if (this.isEmpty()) return null;

        const result = this.data[0];
        const last = this.data.pop();

        if (!this.isEmpty()) {
            this.data[0] = last;
            let i = 0;

            while (true) {
                const left = 2 * i + 1;
                const right = 2 * i + 2;
                let smallest = i;

                if (left < this.data.length && this.comparator(this.data[left], this.data[smallest]) < 0) {
                    smallest = left;
                }

                if (right < this.data.length && this.comparator(this.data[right], this.data[smallest]) < 0) {
                    smallest = right;
                }

                if (smallest === i) break;

                [this.data[i], this.data[smallest]] = [this.data[smallest], this.data[i]];
                i = smallest;
            }
        }

        return result;
    }

    isEmpty() {
        return this.data.length === 0;
    }
}
```


    The algorithm uses Dijkstra's shortest path algorithm to find the path with the minimum effort. Starting from position (0, 0), the algorithm maintains a priority queue of cells to visit, with their current efforts. At each step, the algorithm chooses the cell with the lowest effort, and then tries to move to its neighbors in all four possible directions. When updating the effort of its neighbor, the algorithm only takes into account the highest effort seen so far on its path, which is the maximum absolute difference in heights between two consecutive cells on its path. 

The algorithm maintains a 2D effort array, where efforts[row][col] represents the minimum effort required to reach the cell (row, col). It then pushes these efforts into a priority queue that sorts the cells in non-decreasing order of their efforts.

When the algorithm finally reaches the destination cell (rows-1, columns-1), it returns the corresponding effort.

The time complexity of the algorithm is O(rows*columns*log(rows*columns)), as it potentially visits all cells and uses a priority queue for the processing. The space complexity is O(rows*columns) due to the effort array and priority queue storage.

